#include <iostream>
using namespace std;

int main() {
    int n;
    cin >> n;
    long long result = 1;
    if (n % 2 == 0) {
        for (int i = 2; i <= n; i += 2) {
            result *= i;
        }
    } else {
        for (int i = 1; i <= n; i += 2) {
            result *= i;
        }
    }
    cout << result << endl;
    return 0;
}
